/*
 * garage_door_controller.ino — Garage Door IoT Controller
 *
 * Elements:
 *   1. Magnetic Reed Switch Position Sensors — GPIO 34 (closed), GPIO 35 (open)
 *   2. PIR HC-SR501 Motion Sensor            — GPIO 32
 *   3. Solid-State Relay (SSR)               — GPIO 25 (300 ms pulse)
 *   4. OTA HTTPS Firmware Update             — triggered via MQTT
 *   5. ESP32 WiFi + MQTT Telemetry           — broker 192.168.1.x
 *   6. MQTT QoS-1 Event Logger               — retained messages
 */

#include <Arduino.h>
#include <WiFi.h>
#include <PubSubClient.h>
#include <ArduinoOTA.h>

// --- WiFi + MQTT ---
const char* SSID       = "HomeNet";
const char* WIFI_PASS  = "changeme";
const char* MQTT_HOST  = "192.168.1.10";
const int   MQTT_PORT  = 1883;

// --- Pins ---
#define PIN_CLOSED 34
#define PIN_OPEN   35
#define PIN_PIR    32
#define PIN_SSR    25

// --- MQTT topics ---
#define T_STATE    "garage/door/state"
#define T_CMD      "garage/door/cmd"
#define T_PRESENCE "garage/door/presence"
#define T_LOG      "garage/door/log"

// --- State machine ---
enum DoorState { DOOR_CLOSED, DOOR_OPEN, DOOR_MOVING, DOOR_STUCK };
DoorState door_state = DOOR_CLOSED;
unsigned long move_start_ms = 0;
#define MOVE_TIMEOUT_MS 15000UL
#define SSR_PULSE_MS      300UL

WiFiClient   wifiClient;
PubSubClient mqtt(wifiClient);

volatile bool pos_changed = false;
volatile bool pir_event   = false;

void IRAM_ATTR on_pos()  { pos_changed = true; }
void IRAM_ATTR on_pir()  { pir_event   = true; }

const char* state_str(DoorState s) {
  switch (s) {
    case DOOR_CLOSED:  return "CLOSED";
    case DOOR_OPEN:    return "OPEN";
    case DOOR_MOVING:  return "MOVING";
    default:           return "STUCK";
  }
}

void publish_state(DoorState s) {
  mqtt.publish(T_STATE, state_str(s), true);
  char log_buf[128];
  snprintf(log_buf, sizeof(log_buf),
           "{\"event\":\"state\",\"state\":\"%s\"}", state_str(s));
  mqtt.publish(T_LOG, log_buf, false);
  Serial.printf("Door state: %s\n", state_str(s));
}

void trigger_door() {
  digitalWrite(PIN_SSR, HIGH);
  delay(SSR_PULSE_MS);
  digitalWrite(PIN_SSR, LOW);
  door_state    = DOOR_MOVING;
  move_start_ms = millis();
  publish_state(DOOR_MOVING);
}

void mqtt_callback(char* topic, byte* payload, unsigned int len) {
  char msg[32] = {};
  memcpy(msg, payload, min(len, (unsigned int)31));
  if (String(topic) == T_CMD) {
    if (strcmp(msg, "toggle") == 0) trigger_door();
    else if (strcmp(msg, "ota") == 0) ArduinoOTA.begin();
  }
}

void mqtt_reconnect() {
  while (!mqtt.connected()) {
    if (mqtt.connect("GarageDoor")) {
      mqtt.subscribe(T_CMD);
    } else {
      delay(5000);
    }
  }
}

void setup() {
  Serial.begin(115200);

  pinMode(PIN_CLOSED, INPUT_PULLUP);
  pinMode(PIN_OPEN,   INPUT_PULLUP);
  pinMode(PIN_PIR,    INPUT);
  pinMode(PIN_SSR,    OUTPUT); digitalWrite(PIN_SSR, LOW);

  attachInterrupt(digitalPinToInterrupt(PIN_CLOSED), on_pos, CHANGE);
  attachInterrupt(digitalPinToInterrupt(PIN_OPEN),   on_pos, CHANGE);
  attachInterrupt(digitalPinToInterrupt(PIN_PIR),    on_pir, RISING);

  WiFi.begin(SSID, WIFI_PASS);
  while (WiFi.status() != WL_CONNECTED) delay(500);

  mqtt.setServer(MQTT_HOST, MQTT_PORT);
  mqtt.setCallback(mqtt_callback);
  mqtt_reconnect();

  ArduinoOTA.setHostname("garage-door");
  ArduinoOTA.setPassword("ota-secret");
  // ArduinoOTA.begin() called on demand via MQTT 'ota' command

  // Determine initial door state from reed switches
  if (!digitalRead(PIN_CLOSED))     door_state = DOOR_CLOSED;
  else if (!digitalRead(PIN_OPEN))  door_state = DOOR_OPEN;
  else                               door_state = DOOR_MOVING;
  publish_state(door_state);

  Serial.println(F("Garage door controller ready."));
}

void loop() {
  if (!mqtt.connected()) mqtt_reconnect();
  mqtt.loop();
  ArduinoOTA.handle();

  // --- 1. Reed switch position update ---
  if (pos_changed) {
    pos_changed = false;
    delay(20);  // debounce
    bool closed_limit = !digitalRead(PIN_CLOSED);
    bool open_limit   = !digitalRead(PIN_OPEN);
    DoorState new_state;
    if (closed_limit)  new_state = DOOR_CLOSED;
    else if (open_limit) new_state = DOOR_OPEN;
    else                 new_state = DOOR_MOVING;
    if (new_state != door_state) {
      door_state = new_state;
      publish_state(door_state);
    }
  }

  // --- 2. Movement timeout → stuck ---
  if (door_state == DOOR_MOVING &&
      (millis() - move_start_ms) > MOVE_TIMEOUT_MS) {
    door_state = DOOR_STUCK;
    publish_state(DOOR_STUCK);
  }

  // --- 3. PIR presence ---
  if (pir_event) {
    pir_event = false;
    mqtt.publish(T_PRESENCE, "motion", false);
    char log_buf[64];
    snprintf(log_buf, sizeof(log_buf), "{\"event\":\"presence\"}");
    mqtt.publish(T_LOG, log_buf, false);
  }
}
